
const LESSONS = [{"id": "m0-how-to-use", "module": "0. How to Use Athena", "title": "How to Use Athena Without Wasting Time", "tags": ["study plan", "interview prep", "principal tpm", "learning method"], "analogy": "Think of Athena like a gym plan. You do not read the entire fitness textbook before lifting. You show up, do the right exercises, track progress, and repeat.", "simple": "Use Athena as a daily practice system: learn one concept, explain it out loud, answer one interview question, then connect it to a real system.", "technical": "The curriculum is organized around retrieval, reasoning, tools, evaluation, architecture, governance, and TPM execution. Each topic is taught through analogy, system design, trade-offs, and interview answers.", "principal": "At Principal level, the goal is not memorization. The goal is judgment: choosing the right architecture, explaining trade-offs, managing risk, measuring quality, and driving adoption.", "trap": "Do not treat this as a reading website. Treat it as an interview practice operating system.", "diagram": ["Learn concept", "Explain out loud", "Answer interview question", "Apply to system", "Record weak area", "Repeat"], "interview": "I learn AI by connecting concepts to real systems, then practicing how to explain architecture, trade-offs, risk, and measurable outcomes at different altitudes.", "exercise": "Pick one lesson and explain it in 60 seconds as if speaking to a CTO."}, {"id": "m1-ai-ml-dl", "module": "1. AI Fundamentals", "title": "AI vs Machine Learning vs Deep Learning vs Generative AI", "tags": ["ai", "ml", "deep learning", "generative ai", "foundation models"], "analogy": "AI is the broad goal of making machines act intelligently. Machine learning is teaching from examples. Deep learning is using layered neural networks. Generative AI is asking the system to create something new.", "simple": "AI is the umbrella. ML learns patterns. Deep learning uses neural networks. Generative AI creates text, code, images, audio, or structured outputs.", "technical": "Modern generative AI is usually powered by foundation models trained on large datasets and adapted through prompting, retrieval, tools, fine-tuning, and evaluation.", "principal": "In interviews, separate capability from product. A model is not the product; the product includes UX, retrieval, governance, cost controls, evaluation, and operational workflow.", "trap": "Do not use AI, ML, GenAI, and LLM as interchangeable terms.", "diagram": ["AI", "Machine Learning", "Deep Learning", "Foundation Models", "Generative AI Apps"], "interview": "AI is the broad category. LLMs are one class of foundation model. A production GenAI system wraps the model with context, tools, guardrails, evaluation, and business workflow.", "exercise": "Explain AI vs ML vs GenAI to a non-technical executive."}, {"id": "m1-tokens", "module": "1. AI Fundamentals", "title": "Tokens: The Cost and Context Unit of LLMs", "tags": ["tokens", "cost", "latency", "context window"], "analogy": "You do not eat a whole banana tree; you eat manageable pieces. LLMs do not consume raw paragraphs as one object; they consume chunks called tokens.", "simple": "Tokens are the chunks of text the model reads and writes.", "technical": "Tokens are sub-word units created by a tokenizer. They determine context limits, latency, and cost because both prompt and response are counted in tokens.", "principal": "Token management is platform strategy. Long prompts, repeated context, and bloated retrieval can silently drive cost and latency at scale.", "trap": "Do not treat token cost as only an engineering concern. In enterprise AI, token cost affects pricing, margins, model routing, and UX.", "diagram": ["User text", "Tokenizer", "Tokens", "Model context", "Output tokens", "Cost / latency"], "interview": "Tokens are the model’s unit of text processing. I care about them because they determine context limits, cost, and response time.", "exercise": "Name three ways to reduce token usage without hurting answer quality."}, {"id": "m1-context", "module": "1. AI Fundamentals", "title": "Context Window: The Model’s Working Memory", "tags": ["context window", "long context", "prompt", "memory"], "analogy": "When driving, you focus on the road, GPS, traffic lights, and cars nearby. You are not thinking about every memory from your life.", "simple": "The context window is what the model can see at once.", "technical": "It contains the system instructions, user message, retrieved documents, tool outputs, conversation history, and response budget. Larger windows increase capability but also cost and complexity.", "principal": "The question is not only how large the context window is. The real question is what earns a place in it.", "trap": "Do not say long-context models eliminate RAG. RAG is about relevance, cost, freshness, and governance, not just fitting more text.", "diagram": ["User request", "Relevant history", "Retrieved docs", "Instructions", "Prompt builder", "Context window", "LLM"], "interview": "A context window is the model’s working memory. Good systems curate context rather than dumping everything into the prompt.", "exercise": "Explain why putting an entire database into context is usually a bad idea."}, {"id": "m1-embeddings", "module": "1. AI Fundamentals", "title": "Embeddings and Semantic Search", "tags": ["embeddings", "semantic search", "vectors", "similarity"], "analogy": "One parent says “my baby is burning,” another says “high fever,” another says “temperature 103.” Different words, similar meaning.", "simple": "Embeddings help AI search by meaning, not just exact words.", "technical": "Embeddings convert text or other data into numeric vectors. Similar meanings are placed near each other in vector space and retrieved through similarity search.", "principal": "Embedding strategy includes model choice, chunking, metadata, refresh policy, vector drift, evaluation, hybrid search, and cost of re-embedding.", "trap": "Do not say embeddings replace keyword search. Hybrid search usually combines keyword recall, vector similarity, and reranking.", "diagram": ["Text", "Embedding model", "Vector", "Vector DB", "Similarity search", "Relevant results"], "interview": "Embeddings are numeric representations of meaning. They power semantic search, RAG, deduplication, clustering, and recommendations.", "exercise": "Give one example where keyword search fails but embeddings help."}, {"id": "m1-transformers-attention", "module": "1. AI Fundamentals", "title": "Transformers and Attention", "tags": ["transformers", "attention", "self attention", "llm internals"], "analogy": "When driving, many things are visible, but your brain focuses on brake lights ahead. Attention decides what matters.", "simple": "Attention lets the model focus on relevant parts of the input.", "technical": "Transformers use self-attention so each token can weigh the relevance of other tokens. This enables long-range relationships and efficient parallel training.", "principal": "For TPM interviews, know why attention matters: context understanding, parallelism, scaling, and why Transformers replaced earlier sequence models.", "trap": "Do not drown the interviewer in math unless asked. Explain conceptually first, then offer depth.", "diagram": ["Tokens", "Queries", "Keys", "Values", "Attention weights", "Context-aware representation"], "interview": "Self-attention lets each token ask which other tokens matter to it. That is the core reason Transformers handle context well.", "exercise": "Explain self-attention without using equations."}, {"id": "m1-rag", "module": "1. AI Fundamentals", "title": "RAG: Retrieval-Augmented Generation", "tags": ["rag", "retrieval", "grounding", "citations"], "analogy": "In an interview, you do not replay your whole career. You retrieve the three relevant stories, then answer.", "simple": "RAG retrieves relevant information first, then asks the model to answer.", "technical": "RAG usually involves chunking, embeddings, vector/hybrid retrieval, reranking, prompt assembly, answer generation, citations, and evaluation.", "principal": "RAG is a product and governance choice, not just a technical trick. It helps with freshness, auditability, and source-backed answers.", "trap": "Do not claim RAG eliminates hallucinations. It reduces risk but can still fail through poor retrieval or model misuse of context.", "diagram": ["Question", "Embed query", "Retrieve docs", "Rerank", "Build prompt", "LLM answer", "Citations / validation"], "interview": "RAG lets AI answer from private or changing knowledge without retraining, while preserving source evidence and freshness.", "exercise": "Explain when RAG is better than fine-tuning."}, {"id": "m1-rag-vs-ft", "module": "1. AI Fundamentals", "title": "RAG vs Fine-Tuning", "tags": ["rag", "fine tuning", "lora", "model adaptation"], "analogy": "RAG is handing someone the right open book. Fine-tuning is sending them to school to change how they behave.", "simple": "Use RAG for knowledge. Use fine-tuning for behavior.", "technical": "RAG injects external context at inference time. Fine-tuning updates model weights or adapters to change style, format, or task behavior.", "principal": "Start with prompting and RAG, measure failure patterns, then fine-tune only for repeated behavior gaps that cannot be solved reliably otherwise.", "trap": "Do not describe fine-tuning as the default way to upload enterprise documents.", "diagram": ["Need knowledge?", "RAG", "Need behavior?", "Fine-tune", "Need both?", "Hybrid"], "interview": "I default to RAG for changing, auditable knowledge. I consider fine-tuning for consistent behavior, formatting, or domain-specific task performance.", "exercise": "A team has 10k tickets. Ask five questions before choosing RAG or fine-tuning."}, {"id": "m1-prompting-structured-output", "module": "1. AI Fundamentals", "title": "Prompt Engineering and Structured Outputs", "tags": ["prompt engineering", "structured output", "json schema", "guardrails"], "analogy": "If you ask a contractor “fix the house,” you get vague answers. If you provide a checklist and inspection format, the output becomes usable.", "simple": "Good prompts define role, goal, context, constraints, and output format.", "technical": "Production systems often use prompt templates, JSON schemas, function/tool calls, validators, retries, and deterministic post-processing.", "principal": "The goal is reliability. Free-form prompting is not enough for enterprise workflows that need repeatability and auditability.", "trap": "Do not oversell prompt engineering as the whole solution. It is one layer in a system.", "diagram": ["User goal", "Prompt template", "Schema", "LLM", "Validator", "Structured output"], "interview": "For production AI, I prefer schema-constrained outputs and validation over free-form text wherever the response drives a workflow.", "exercise": "Design a JSON output schema for summarizing a customer complaint."}, {"id": "m2-chatgpt", "module": "2. How Modern AI Systems Work", "title": "How ChatGPT Works as an Application", "tags": ["chatgpt", "llm app", "request lifecycle", "tools"], "analogy": "You give GPS a destination; it handles route, traffic, rerouting, and arrival guidance.", "simple": "ChatGPT is not just a model. It is a full application around a model.", "technical": "The application handles auth, conversation state, system instructions, prompt construction, tool selection, retrieval, inference, safety, streaming, and UI rendering.", "principal": "Enterprise versions require audit logs, policy enforcement, tenant isolation, data controls, evals, and cost attribution.", "trap": "Do not explain ChatGPT only as next-token prediction in a senior architecture interview.", "diagram": ["User", "App layer", "Context builder", "Tools/Retrieval", "Model", "Safety/Validation", "Streaming UI"], "interview": "A ChatGPT-style system wraps the model with orchestration, context, tools, memory, safety, evaluation, and user experience.", "exercise": "Draw the lifecycle of one ChatGPT request."}, {"id": "m2-cursor", "module": "2. How Modern AI Systems Work", "title": "How Cursor Understands a Codebase", "tags": ["cursor", "coding assistant", "code retrieval", "context engineering"], "analogy": "A contractor checks the room, wiring, blueprint, and recent changes before fixing the house.", "simple": "Cursor retrieves relevant code context before asking the model to make changes.", "technical": "Coding assistants use file indexing, embeddings, syntax trees, retrieval, prompt construction, tool calls, diff generation, and tests/review loops.", "principal": "The value is not code generation alone. The value is accurate context selection, safe patching, verification, and developer workflow integration.", "trap": "Do not say Cursor just writes code. Say it retrieves context, proposes a patch, and requires validation.", "diagram": ["Prompt", "Repo index", "Relevant files", "Context pack", "LLM plan", "Patch", "Tests / review"], "interview": "AI coding assistants are RAG-plus-tools systems over source code, with patch generation and verification loops.", "exercise": "Explain why wrong file retrieval causes bad AI coding output."}, {"id": "m2-copilot", "module": "2. How Modern AI Systems Work", "title": "How GitHub Copilot-Style Autocomplete Works", "tags": ["copilot", "autocomplete", "developer tools", "latency"], "analogy": "A driving assistant suggests the next turn before you ask because it sees where you are and where you are likely going.", "simple": "Copilot predicts useful code from local context.", "technical": "Autocomplete systems optimize for low latency, relevant file context, coding patterns, model routing, and inline UX.", "principal": "The product challenge is balancing helpfulness with distraction, speed with quality, and privacy with context depth.", "trap": "Do not evaluate coding assistants only by whether they produce code. Evaluate acceptance rate, correctness, security, and developer flow impact.", "diagram": ["Editor context", "Nearby code", "Model suggestion", "Developer accepts/edits", "Telemetry", "Improvement loop"], "interview": "Autocomplete AI is a low-latency context prediction system embedded into the developer workflow.", "exercise": "List metrics for measuring a coding assistant."}, {"id": "m2-perplexity", "module": "2. How Modern AI Systems Work", "title": "How AI Search Engines Work", "tags": ["ai search", "perplexity", "web retrieval", "citations"], "analogy": "Instead of asking one friend from memory, you ask a librarian to collect current sources, then summarize them with citations.", "simple": "AI search combines live retrieval with answer generation.", "technical": "It uses query understanding, web/document retrieval, ranking, summarization, citation generation, freshness handling, and source quality controls.", "principal": "The hardest parts are source trust, freshness, citation fidelity, latency, and avoiding confident synthesis from weak evidence.", "trap": "Do not treat citations as proof by themselves. The cited source must actually support the claim.", "diagram": ["Query", "Search/Retrieve", "Rank sources", "Summarize", "Cite", "Answer"], "interview": "AI search is RAG over open or curated sources with emphasis on freshness, source quality, and citation-grounded answers.", "exercise": "Explain how you would evaluate citation quality."}, {"id": "m2-voice-ai", "module": "2. How Modern AI Systems Work", "title": "How Voice AI and Realtime Assistants Work", "tags": ["voice ai", "stt", "tts", "realtime", "webrtc"], "analogy": "A phone conversation requires hearing, understanding, deciding when the other person stopped talking, and speaking back naturally.", "simple": "Voice AI adds speech input, turn detection, and speech output around the AI reasoning loop.", "technical": "Voice systems use audio capture, VAD, speech-to-text, LLM reasoning, text-to-speech, streaming, latency optimization, and session management.", "principal": "The product challenge is latency, interruption handling, cost, safety, and user trust in high-stakes conversations.", "trap": "Do not focus only on transcription. Realtime voice quality depends on the entire loop.", "diagram": ["Mic", "VAD", "STT", "LLM", "Tools/Memory", "TTS", "Speaker"], "interview": "Voice AI is a multimodal orchestration problem: audio in, language reasoning, tools, safety, audio out, all under tight latency constraints.", "exercise": "Name three failure modes in voice AI."}, {"id": "m3-ai-gateway", "module": "3. Enterprise AI", "title": "AI Gateway and Model Access Layer", "tags": ["ai gateway", "model routing", "governance", "enterprise ai"], "analogy": "In an office, visitors do not walk directly into every room. They go through reception, badge checks, approvals, and logs.", "simple": "An AI gateway controls how teams access models.", "technical": "It centralizes auth, routing, policy, logging, rate limits, cost tracking, prompt management, eval hooks, and vendor abstraction.", "principal": "A gateway turns scattered model calls into a governed enterprise platform.", "trap": "Do not reduce an AI gateway to a proxy. It is a control plane for AI adoption.", "diagram": ["Apps", "AI Gateway", "Policy", "Model Router", "Vendors", "Logs/Evals/Cost"], "interview": "An AI gateway provides secure, observable, governed access to models across the enterprise.", "exercise": "Define the minimum features of an enterprise AI gateway."}, {"id": "m3-model-routing", "module": "3. Enterprise AI", "title": "Model Routing and Multi-Model Strategy", "tags": ["model routing", "multi model", "openai", "anthropic", "gemini"], "analogy": "You do not send every package by the fastest courier. Some need speed, some need low cost, some need special handling.", "simple": "Route each task to the right model.", "technical": "Routing considers capability, cost, latency, context length, data policy, reliability, and fallback paths.", "principal": "Model routing protects margins and reliability while avoiding vendor lock-in.", "trap": "Do not assume the biggest model is always best.", "diagram": ["Request type", "Policy", "Small model", "Large model", "Specialized model", "Fallback"], "interview": "I would route by workload: cheap models for simple tasks, stronger models for reasoning, specialized models for vision/audio/code, with eval-based routing policies.", "exercise": "Create a routing policy for summarization, extraction, coding, and reasoning."}, {"id": "m3-cost", "module": "3. Enterprise AI", "title": "AI Cost and Token Governance", "tags": ["cost", "tokens", "budget", "rate limit", "caching"], "analogy": "If every employee takes a limousine for every errand, the travel budget explodes.", "simple": "AI cost governance means knowing where tokens and model calls go.", "technical": "Controls include token attribution, caching, model routing, quotas, batching, prompt compression, retrieval limits, and alerts.", "principal": "Cost governance is both technical and product strategy: it determines pricing, margins, user limits, and rollout feasibility.", "trap": "Do not wait until the bill spikes to design cost controls.", "diagram": ["Usage", "Token attribution", "Budget rules", "Routing", "Caching", "Alerts"], "interview": "I manage AI cost by measuring spend per workload, then using model routing, caching, prompt optimization, and quotas.", "exercise": "Explain how to cut LLM cost by 30% without reducing quality."}, {"id": "m3-security", "module": "3. Enterprise AI", "title": "AI Security, Privacy, and Prompt Injection", "tags": ["security", "privacy", "prompt injection", "data leakage"], "analogy": "A hotel guest should not be able to walk behind the front desk just because they asked politely.", "simple": "AI systems need boundaries because users can try to manipulate prompts, tools, and data access.", "technical": "Risks include prompt injection, data exfiltration, unsafe tool calls, overbroad retrieval, PII leakage, and cross-tenant exposure.", "principal": "Security must be designed at the tool, retrieval, policy, identity, and audit layers — not only in the prompt.", "trap": "Do not say “we told the model not to reveal secrets” as a security control.", "diagram": ["User input", "Policy check", "Retriever scope", "Tool permissions", "LLM", "Audit"], "interview": "I would treat the LLM as untrusted. Enforce identity, permissions, retrieval scope, tool contracts, validation, and audit outside the model.", "exercise": "Name three defenses against prompt injection."}, {"id": "m3-evaluation", "module": "3. Enterprise AI", "title": "AI Evaluation and Production Readiness", "tags": ["evaluation", "evals", "golden dataset", "llm judge", "regression"], "analogy": "You would not ship a car because it feels fast. You test braking, safety, mileage, reliability, and cost.", "simple": "Evals turn vibes into measurable quality.", "technical": "Evaluation includes golden datasets, human review, LLM-as-judge, regression tests, online metrics, latency, cost, and safety scoring.", "principal": "Evaluation is the backbone of model upgrades, prompt changes, vendor comparisons, and production confidence.", "trap": "Do not rely only on demo quality.", "diagram": ["Golden set", "Model output", "Scoring rubric", "Human calibration", "Regression report", "Launch gate"], "interview": "Before launching AI, I need measurable quality, regression tests, and monitoring across accuracy, groundedness, safety, latency, and cost.", "exercise": "Design an eval plan for a RAG assistant."}, {"id": "m3-observability", "module": "3. Enterprise AI", "title": "AI Observability", "tags": ["observability", "tracing", "latency", "quality", "monitoring"], "analogy": "A hospital monitor shows heart rate, oxygen, and blood pressure. You need the same visibility for AI systems.", "simple": "AI observability lets you see what happened inside a request.", "technical": "It includes traces, prompts, retrieved docs, tool calls, model versions, latency, token usage, errors, and quality scores.", "principal": "Without observability, debugging AI is guesswork. It is essential for incident response and continuous improvement.", "trap": "Do not monitor only uptime. AI can be up and still wrong.", "diagram": ["Request", "Trace", "Retrieval", "Tool calls", "Model output", "Scores", "Dashboard"], "interview": "I would instrument AI requests end-to-end so quality, cost, latency, and failure modes are observable.", "exercise": "List the fields you would log for an AI request."}, {"id": "m3-model-upgrade", "module": "3. Enterprise AI", "title": "Running a Model Upgrade Program", "tags": ["model upgrade", "program management", "canary", "shadow", "rollout"], "analogy": "You do not replace the engine on every company vehicle overnight. You test, compare, canary, and keep rollback ready.", "simple": "A model upgrade is a program, not a config change.", "technical": "It needs baseline evals, shadow testing, canary rollout, prompt compatibility checks, cost/latency comparison, rollback, and stakeholder communication.", "principal": "Newer is not automatically better. Prove it on your data and workflows.", "trap": "Do not upgrade models purely because a vendor announced a better benchmark.", "diagram": ["Baseline", "Shadow", "Eval compare", "Canary", "Monitor", "Rollback / expand"], "interview": "I would treat model migration like a controlled rollout with eval gates, canaries, rollback, cost tracking, and stakeholder communication.", "exercise": "Draft a 5-step model upgrade plan."}, {"id": "m4-healthcare-ai", "module": "4. AI Architecture", "title": "Design a Safe Healthcare AI Assistant", "tags": ["healthcare ai", "safety", "human in the loop", "guardrails"], "analogy": "A nurse intake line gathers facts, checks red flags, and routes appropriately. It does not pretend to replace the doctor.", "simple": "Healthcare AI should assist intake, summary, and escalation — not make unsupported clinical claims.", "technical": "Architecture includes intake, structured facts, deterministic safety checks, retrieval from records, model summarization, escalation, audit, and clinician handoff.", "principal": "The critical design boundary is between conversational help and safety-critical decisioning.", "trap": "Do not say the AI diagnoses. Say it supports structured intake and communication with appropriate safety boundaries.", "diagram": ["Concern", "Clarify", "Facts", "Safety checks", "Relevant records", "Summary", "Escalate"], "interview": "I would separate LLM conversation from deterministic safety logic, preserve auditability, and escalate high-risk cases to human care.", "exercise": "Name five safety requirements for healthcare AI."}, {"id": "m4-regulated-evidence", "module": "4. AI Architecture", "title": "Design a Regulated Evidence-Handling AI Platform", "tags": ["regulated ai", "evidence", "audit", "extraction", "compliance"], "analogy": "In court, a claim is not enough. You need evidence, provenance, chain of custody, and review.", "simple": "Regulated AI must preserve why it produced an answer, not just the answer.", "technical": "Architecture includes source ingestion, extraction, normalization, evidence links, validation rules, reviewer workflow, audit trail, and downstream integration.", "principal": "The hard problem is combining probabilistic AI with deterministic controls in a way reviewers can trust.", "trap": "Do not say “AI automates compliance.” Say AI assists, structures, and surfaces evidence while governance controls the workflow.", "diagram": ["Source", "Extraction", "Evidence link", "Validation", "Reviewer", "Audit", "System of record"], "interview": "In regulated AI, I design for source-backed outputs, deterministic gates, human review, and auditability from day one.", "exercise": "Explain why evidence links matter in regulated AI."}, {"id": "m4-document-ai", "module": "4. AI Architecture", "title": "Design a Document Extraction System", "tags": ["document ai", "ocr", "extraction", "classification", "validation"], "analogy": "A clerk receives messy forms, scans them, identifies the form type, extracts fields, checks missing values, and sends exceptions to review.", "simple": "Document AI turns messy inputs into structured, reviewable data.", "technical": "Pipeline: ingest, classify, OCR/vision, extract, normalize, validate, confidence score, route exceptions, store evidence, and monitor quality.", "principal": "Start with the simplest reliable approach, measure error profile, and add complexity only where volume or accuracy demands it.", "trap": "Do not fine-tune on day one without proving the error pattern and ROI.", "diagram": ["Upload", "Classify", "OCR/Vision", "Extract", "Normalize", "Validate", "Review"], "interview": "I would phase document extraction: prove value quickly, measure errors, then invest in owned OCR/layout/fine-tuning only when justified.", "exercise": "Name metrics for document extraction quality."}, {"id": "m4-enterprise-search", "module": "4. AI Architecture", "title": "Design Enterprise AI Search", "tags": ["enterprise search", "hybrid search", "rag", "permissions"], "analogy": "A company library must return the right document, but only to people allowed to see it.", "simple": "Enterprise search needs relevance and permissions.", "technical": "Architecture includes connectors, indexing, chunking, embeddings, metadata, ACL filtering, hybrid retrieval, reranking, citations, feedback, and evals.", "principal": "Security and relevance are inseparable. Retrieval must respect identity and access controls.", "trap": "Do not build semantic search without permission filtering.", "diagram": ["Connectors", "Index", "ACL metadata", "Query", "Hybrid retrieval", "Rerank", "Cited answer"], "interview": "Enterprise search is not just vector search; it needs connectors, permissions, metadata, ranking, citations, and quality evaluation.", "exercise": "Explain how ACL filtering changes RAG architecture."}, {"id": "m5-ai-product-metrics", "module": "5. AI Product Leadership", "title": "AI Product Metrics", "tags": ["product metrics", "adoption", "trust", "roi"], "analogy": "A fitness app is not successful because it has many features. It is successful if people keep using it and get healthier.", "simple": "AI product success requires quality, adoption, trust, and business outcome metrics.", "technical": "Metrics include task completion, deflection, time saved, acceptance rate, correction rate, groundedness, user trust, cost per successful task, retention, and escalation rate.", "principal": "Avoid vanity metrics. Tie AI outcomes to user workflow and business value.", "trap": "Do not use token volume as a success metric by itself.", "diagram": ["User need", "AI task", "Outcome", "Quality", "Adoption", "Business value"], "interview": "I measure AI products by successful task completion, trust, quality, cost, and business impact — not just usage.", "exercise": "Define metrics for an AI document assistant."}, {"id": "m5-roadmap", "module": "5. AI Product Leadership", "title": "AI Roadmap and Prioritization", "tags": ["roadmap", "prioritization", "mvp", "strategy"], "analogy": "When planning a trip, you choose the must-see places first, not every possible stop.", "simple": "AI roadmap prioritization should focus on high-value, measurable workflows.", "technical": "Prioritize by user pain, feasibility, data readiness, risk, eval ability, cost, compliance, and feedback loops.", "principal": "The best AI roadmap starts with narrow workflows where quality can be measured and value is clear.", "trap": "Do not build generic chat before identifying valuable jobs-to-be-done.", "diagram": ["User pain", "Data readiness", "Risk", "Measurable value", "MVP", "Iteration"], "interview": "I prioritize AI use cases where the workflow is painful, data is available, success is measurable, and risk can be bounded.", "exercise": "Rank three AI features using value, feasibility, and risk."}, {"id": "m6-tpm-ai-program", "module": "6. AI TPM / Program Management", "title": "Running an AI Program", "tags": ["tpm", "program management", "ai roadmap", "execution"], "analogy": "Running a construction project requires architects, permits, contractors, inspectors, budget, and timeline — not just a blueprint.", "simple": "AI TPM work connects product, engineering, data, legal, security, and business teams.", "technical": "AI programs need milestones, dependencies, eval gates, launch criteria, risk tracking, vendor coordination, adoption plans, and executive reporting.", "principal": "The TPM differentiator is turning uncertain AI capability into a governed, measurable delivery program.", "trap": "Do not manage AI like a normal feature with only date/status tracking.", "diagram": ["Strategy", "Use cases", "Data", "Engineering", "Evals", "Governance", "Rollout"], "interview": "I run AI programs by defining measurable outcomes, aligning teams, building eval gates, managing risk, and rolling out incrementally.", "exercise": "Draft an AI program status update."}, {"id": "m6-vendor", "module": "6. AI TPM / Program Management", "title": "AI Vendor Management", "tags": ["vendor", "openai", "anthropic", "azure", "bedrock", "contracts"], "analogy": "You do not choose a school only by the brochure. You check teachers, outcomes, cost, support, and fit.", "simple": "Vendor choice depends on capability, risk, cost, compliance, and roadmap.", "technical": "Assess models, data terms, security, latency, SLAs, regional availability, eval performance, cost, support, integration, and exit strategy.", "principal": "Avoid vendor lock-in by abstracting access and benchmarking providers against your own workloads.", "trap": "Do not choose a vendor only by public benchmarks.", "diagram": ["Requirements", "Eval set", "Vendor tests", "Security review", "Cost model", "Contract", "Rollout"], "interview": "I evaluate vendors on real workloads, not hype: quality, cost, latency, security, data terms, support, and strategic fit.", "exercise": "Create a vendor scorecard."}, {"id": "m7-system-design-chatgpt", "module": "7. System Design", "title": "System Design: ChatGPT-Like Assistant", "tags": ["system design", "chatgpt", "assistant", "architecture"], "analogy": "A concierge listens, checks records, calls services, follows policy, and responds clearly.", "simple": "Design the assistant as an orchestration system around a model.", "technical": "Components: frontend, auth, session store, intent router, prompt builder, retrieval, tools, model gateway, safety, streaming, logging, evals.", "principal": "Focus on reliability, scale, security, cost, and model-independent design.", "trap": "Do not start with model internals. Start with requirements and system boundaries.", "diagram": ["Client", "API", "Session", "Intent", "Tools/RAG", "Model gateway", "Validation", "Stream"], "interview": "I would design the assistant as an application platform: context, tools, retrieval, model access, validation, observability, and governance.", "exercise": "Whiteboard ChatGPT in 10 boxes."}, {"id": "m7-system-design-gateway", "module": "7. System Design", "title": "System Design: Enterprise AI Gateway", "tags": ["system design", "ai gateway", "platform", "governance"], "analogy": "A corporate security desk manages visitors, badges, approvals, logs, and restricted areas.", "simple": "The AI gateway centralizes model access and governance.", "technical": "Design includes API gateway, auth, policy engine, routing, vendor adapters, prompt registry, eval hooks, logging, quotas, cost dashboards, and admin console.", "principal": "The value is platform leverage: many teams use AI safely without rebuilding controls.", "trap": "Do not build only a pass-through proxy.", "diagram": ["Apps", "Gateway", "Policy", "Router", "Model adapters", "Logs", "Evals", "Cost"], "interview": "An enterprise AI gateway should provide secure, observable, policy-controlled, cost-aware access to models.", "exercise": "List must-have vs nice-to-have gateway features."}, {"id": "m7-system-design-coding", "module": "7. System Design", "title": "System Design: AI Coding Assistant", "tags": ["system design", "coding assistant", "cursor", "copilot"], "analogy": "A senior engineer first reads the codebase, understands constraints, proposes a change, then tests it.", "simple": "The coding assistant must retrieve code, generate patches, and verify changes.", "technical": "Components: IDE extension, repo index, code embeddings, syntax-aware retrieval, prompt builder, model, patch generator, test runner, review UI, telemetry.", "principal": "Measure accepted changes, correctness, test pass rate, security findings, and developer productivity.", "trap": "Do not optimize only for generating more code.", "diagram": ["IDE", "Repo index", "Retriever", "Prompt", "Model", "Patch", "Tests", "Review"], "interview": "AI coding assistants combine retrieval over code, model reasoning, patch generation, and verification loops.", "exercise": "Design evals for a coding assistant."}, {"id": "m8-interview-playbook", "module": "8. Interview Masterclass", "title": "Principal AI TPM Interview Playbook", "tags": ["interview", "principal tpm", "behavioral", "system design"], "analogy": "A great interview is like a courtroom argument: clear claim, evidence, trade-offs, and calm response to cross-examination.", "simple": "Answer with structure: problem, constraints, decision, trade-offs, outcome, lesson.", "technical": "Prepare across four buckets: concepts, system design, program execution, and leadership stories.", "principal": "Principal candidates are judged on judgment under uncertainty, not just knowledge.", "trap": "Do not overclaim hands-on depth. Be precise about what you led, designed, influenced, and validated.", "diagram": ["Question", "Frame", "Architecture", "Trade-off", "Metrics", "Risk", "Outcome"], "interview": "I approach AI interviews by grounding every answer in architecture, measurable quality, risk management, and business impact.", "exercise": "Record yourself answering one question in 2 minutes."}, {"id": "m8-story-builder", "module": "8. Interview Masterclass", "title": "Story Builder: Four Altitudes", "tags": ["story", "behavioral", "architecture story", "leadership"], "analogy": "You explain a city differently from an airplane, a car, a sidewalk, and inside one building.", "simple": "Every project needs multiple versions depending on the interviewer’s altitude.", "technical": "Prepare 30-second, 2-minute, whiteboard, and deep-dive versions. Each should include problem, scale, architecture, decision, trade-off, risk, metric, and lesson.", "principal": "Your story must show judgment: what you did not build is often as important as what you built.", "trap": "Do not give a product tour. Tell a decision story.", "diagram": ["30 sec", "2 min", "Whiteboard", "Deep dive", "Follow-up defense"], "interview": "My strongest stories are structured around hard decisions, not feature lists.", "exercise": "Fill the private story vault for one flagship project."}];
const SYSTEM_DESIGNS = [{"title": "Design a RAG Platform", "steps": ["Clarify users and data sources", "Ingest and chunk documents", "Embed and index with metadata", "Apply ACL filtering", "Retrieve and rerank", "Generate with citations", "Evaluate groundedness and recall", "Monitor quality and cost"], "tradeoffs": ["Chunk size vs precision", "Hybrid vs vector only", "Freshness vs cost", "Long context vs retrieval", "Latency vs reranking"], "answer": "A RAG platform must solve ingestion, retrieval quality, permissions, citation fidelity, evaluation, and observability."}, {"title": "Design an AI Gateway", "steps": ["Define consumers", "Create model access API", "Add auth and policy engine", "Implement model routing", "Add prompt registry", "Log traces and cost", "Attach eval hooks", "Roll out with quotas"], "tradeoffs": ["Centralization vs team flexibility", "Vendor abstraction vs provider-specific features", "Cost vs quality", "Governance vs speed"], "answer": "An AI gateway is the enterprise control plane for model usage, not just a proxy."}, {"title": "Design a Healthcare AI Assistant", "steps": ["Clarify safety boundaries", "Collect structured intake", "Run deterministic red-flag checks", "Retrieve relevant records", "Generate summary", "Escalate high-risk cases", "Log evidence and decisions", "Evaluate safety and usefulness"], "tradeoffs": ["Helpfulness vs safety", "Conversation vs deterministic rules", "Automation vs clinician review", "Latency vs completeness"], "answer": "Healthcare AI must separate conversation from safety-critical decisioning."}, {"title": "Design a Document Extraction System", "steps": ["Ingest sources", "Classify document type", "OCR or vision extraction", "Normalize fields", "Validate required data", "Score confidence", "Route exceptions", "Store evidence"], "tradeoffs": ["Hosted vision vs owned OCR", "Speed vs accuracy", "Automation vs review", "Generic extraction vs fine-tuned models"], "answer": "Document AI should start simple, measure errors, and add complexity only where justified."}, {"title": "Design an AI Coding Assistant", "steps": ["Index repo", "Retrieve relevant files", "Build prompt", "Generate plan", "Generate patch", "Run tests", "Show diff", "Collect feedback"], "tradeoffs": ["Context breadth vs latency", "Autocomplete vs agentic edits", "Safety vs speed", "Model strength vs cost"], "answer": "Coding assistants are retrieval-plus-tool systems with patch validation loops."}, {"title": "Design AI Search", "steps": ["Understand query intent", "Retrieve sources", "Rank and rerank", "Summarize", "Attach citations", "Validate support", "Collect feedback", "Improve index"], "tradeoffs": ["Freshness vs latency", "Citation fidelity vs answer fluency", "Web scale vs trusted sources", "Recall vs precision"], "answer": "AI search is RAG with stronger emphasis on freshness, source quality, and citations."}];
const INTERVIEWS = [{"category": "Concept", "question": "Explain RAG.", "answer": "RAG retrieves relevant information at query time and gives it to the model so answers are grounded in current or private data."}, {"category": "Concept", "question": "Explain embeddings to a CEO.", "answer": "Embeddings let the system search by meaning, so similar ideas can be found even when the words are different."}, {"category": "Concept", "question": "What is a context window?", "answer": "It is the model’s working memory: everything it can see for a single response."}, {"category": "Concept", "question": "Does RAG eliminate hallucination?", "answer": "No. It reduces hallucination risk but retrieval can miss and models can still misuse context."}, {"category": "Concept", "question": "What is function calling?", "answer": "It is a structured way for the model to request an external tool or API with defined inputs."}, {"category": "Concept", "question": "What is MCP?", "answer": "MCP is a protocol-style approach for connecting AI assistants to tools and data sources consistently."}, {"category": "Concept", "question": "What is agentic AI?", "answer": "Agentic AI can plan, call tools, observe results, and continue toward a goal."}, {"category": "Decision", "question": "RAG or fine-tuning?", "answer": "RAG for knowledge, fine-tuning for behavior. Start with RAG when data changes and needs auditability."}, {"category": "Decision", "question": "When not to use agents?", "answer": "When the workflow steps are known and need to be cheap, testable, and auditable."}, {"category": "Decision", "question": "Which model should we use?", "answer": "Choose based on task quality, latency, cost, context, data policy, and eval results on your workload."}, {"category": "Decision", "question": "Build vs buy?", "answer": "Buy commodity infrastructure; build differentiating workflow, data, and governance capabilities."}, {"category": "Decision", "question": "Long context or retrieval?", "answer": "Use retrieval for relevance and cost control; long context can help but should not replace context selection."}, {"category": "Program", "question": "How do you run model upgrade?", "answer": "Baseline, evaluate, shadow, canary, monitor, communicate, and preserve rollback."}, {"category": "Program", "question": "RAG quality dropped. What do you do?", "answer": "Debug model version, retrieval, embeddings, metadata filters, reranker, prompt, context length, and eval set."}, {"category": "Program", "question": "How do you govern AI cost?", "answer": "Measure token spend by feature, apply model routing, caching, quotas, prompt compression, and retrieval limits."}, {"category": "Program", "question": "How do you handle vendor risk?", "answer": "Use abstraction, workload-specific evals, contract review, fallback plans, and avoid relying on public benchmarks only."}, {"category": "Program", "question": "How do you report AI progress to executives?", "answer": "Report business outcome, quality metrics, risk, cost, adoption, blockers, and next decision needed."}, {"category": "System Design", "question": "Design ChatGPT.", "answer": "Client, auth, session, context builder, tools/RAG, model gateway, safety, streaming, observability."}, {"category": "System Design", "question": "Design enterprise search.", "answer": "Connectors, indexing, ACLs, embeddings, hybrid retrieval, reranking, citations, feedback, evals."}, {"category": "System Design", "question": "Design AI gateway.", "answer": "API, auth, policy, routing, vendor adapters, logs, prompt registry, eval hooks, quotas, dashboard."}, {"category": "System Design", "question": "Design healthcare AI assistant.", "answer": "Structured intake, safety rules, retrieval, summarization, escalation, audit, clinician handoff."}, {"category": "System Design", "question": "Design coding assistant.", "answer": "IDE integration, repo index, retriever, prompt builder, model, patch generation, tests, review UI."}, {"category": "Behavioral", "question": "Tell me about technical uncertainty.", "answer": "Frame options, decision criteria, what you chose, risk mitigation, outcome, and lesson."}, {"category": "Behavioral", "question": "Tell me about executive alignment.", "answer": "Explain how you translated technical risk into business decisions and drove agreement."}, {"category": "Behavioral", "question": "Tell me about a failed AI feature.", "answer": "Discuss eval failure, root cause, what changed, and how governance improved."}, {"category": "Behavioral", "question": "Tell me about influencing without authority.", "answer": "Show cross-functional alignment across product, engineering, security, legal, and business."}, {"category": "Behavioral", "question": "What is your AI leadership philosophy?", "answer": "Use AI where it improves workflow measurably, with guardrails, evals, and human accountability."}];
const GLOSSARY = {"AI": "Broad field of building systems that perform tasks associated with intelligence.", "Machine Learning": "Systems learn patterns from data instead of being explicitly programmed for every rule.", "Deep Learning": "Machine learning using multi-layer neural networks.", "Foundation Model": "Large model trained broadly and adapted to many downstream tasks.", "LLM": "Large language model trained to process and generate text-like tokens.", "Token": "Chunk of text processed by a model.", "Context Window": "The amount of information the model can consider at once.", "Embedding": "Numeric representation of meaning.", "Vector Database": "Database optimized for similarity search over vectors.", "Semantic Search": "Search based on meaning rather than exact keywords.", "Hybrid Search": "Combination of keyword and vector search.", "Reranker": "Model that reorders retrieved results for relevance.", "RAG": "Retrieval-Augmented Generation: retrieve first, generate second.", "Fine-Tuning": "Training that changes model behavior or task performance.", "LoRA": "Parameter-efficient fine-tuning technique.", "Prompt Engineering": "Designing instructions and context for model behavior.", "System Prompt": "High-priority instruction that shapes model behavior.", "Structured Output": "Model response constrained to a schema such as JSON.", "Function Calling": "Model requests a predefined function/tool with structured arguments.", "Tool Calling": "Using external tools such as search, databases, or APIs.", "Agent": "System that can plan, use tools, observe results, and continue.", "Workflow": "Known sequence of steps, often more controllable than an agent.", "MCP": "Model Context Protocol-style approach for connecting tools/data to AI assistants.", "Guardrails": "Rules and controls that constrain or validate AI behavior.", "Prompt Injection": "Malicious or accidental instruction that attempts to override intended behavior.", "Groundedness": "Whether an answer is supported by provided sources.", "Faithfulness": "Whether a generated answer accurately reflects the source context.", "Hallucination": "Unsupported or incorrect model output.", "Golden Dataset": "Curated test set used for evaluation and regression testing.", "LLM-as-Judge": "Using a model to score outputs against a rubric.", "Observability": "Tracing and monitoring AI requests, prompts, retrieval, tools, costs, and outputs.", "AI Gateway": "Central access, policy, routing, logging, and governance layer for models.", "Model Router": "Component selecting the right model for a task.", "Canary Rollout": "Limited rollout to reduce launch risk.", "Shadow Mode": "Testing new behavior without affecting users.", "Human-in-the-Loop": "Human review or approval at critical points.", "Audit Trail": "Record of actions, inputs, outputs, decisions, and evidence.", "PII": "Personally identifiable information.", "PHI": "Protected health information.", "Latency": "Time it takes to return a result.", "p95": "Latency percentile where 95% of requests are faster.", "Cost per Task": "Cost to complete one successful AI workflow.", "Acceptance Rate": "How often users accept AI suggestions.", "Task Completion": "Whether the user successfully achieved the intended goal."};

const $ = (id) => document.getElementById(id);
const storeKey = "athena_v2_progress";
const notesKey = "athena_v2_notes";
let progress = JSON.parse(localStorage.getItem(storeKey) || "{}");
let notes = JSON.parse(localStorage.getItem(notesKey) || "{}");

$("lesson-count").textContent = LESSONS.length;
$("question-count").textContent = INTERVIEWS.length;
$("glossary-count").textContent = Object.keys(GLOSSARY).length;

function saveProgress() { localStorage.setItem(storeKey, JSON.stringify(progress)); }
function saveNotes() { localStorage.setItem(notesKey, JSON.stringify(notes)); }

function moduleList() { return [...new Set(LESSONS.map(l => l.module))]; }

function renderFilters() {
  const wrap = $("module-filters");
  wrap.innerHTML = `<button class="active" data-module="all">All</button>` + moduleList().map(m => `<button data-module="${m}">${m}</button>`).join("");
  wrap.querySelectorAll("button").forEach(btn => btn.onclick = () => {
    wrap.querySelectorAll("button").forEach(b=>b.classList.remove("active"));
    btn.classList.add("active");
    renderLessons(btn.dataset.module);
  });
}

function renderLessons(module="all") {
  const grid = $("lesson-grid");
  const items = module==="all" ? LESSONS : LESSONS.filter(l=>l.module===module);
  grid.innerHTML = items.map(l => `
    <article class="card lesson-card" data-id="${l.id}">
      <span class="pill">${progress[l.id] ? "Done" : "Lesson"}</span>
      <h3>${l.title}</h3>
      <p>${l.module}</p>
      <p class="small">${l.simple}</p>
    </article>`).join("");
  grid.querySelectorAll(".lesson-card").forEach(card => card.onclick = () => openLesson(card.dataset.id));
}

function flowDiagram(steps) {
  return `<div class="diagram">${steps.map((s,i)=>`<div>${s}</div>${i<steps.length-1?'<span>→</span>':''}`).join("")}</div>`;
}

function openLesson(id) {
  const l = LESSONS.find(x=>x.id===id);
  if(!l) return;
  const note = notes[id] || "";
  $("active-lesson").innerHTML = `
    <div class="lesson-header">
      <span class="eyebrow">${l.module}</span>
      <h2>${l.title}</h2>
      <p>${l.tags.map(t=>`#${t}`).join(" ")}</p>
    </div>
    ${flowDiagram(l.diagram)}
    <div class="lesson-grid">
      <div class="lesson-block story"><h3>Real-life analogy</h3><p>${l.analogy}</p></div>
      <div class="lesson-block"><h3>Simple explanation</h3><p>${l.simple}</p></div>
      <div class="lesson-block"><h3>Technical explanation</h3><p>${l.technical}</p></div>
      <div class="lesson-block"><h3>Principal thinking</h3><p>${l.principal}</p></div>
      <div class="lesson-block trap"><h3>Trap to avoid</h3><p>${l.trap}</p></div>
      <div class="lesson-block"><h3>Interview answer</h3><p>${l.interview}</p></div>
    </div>
    <div class="lesson-block exercise"><h3>Practice exercise</h3><p>${l.exercise}</p></div>
    <div class="note-box">
      <label>Your private notes for this lesson</label>
      <textarea id="lesson-note">${note}</textarea>
      <div class="save-row">
        <button class="button primary" id="mark-done">${progress[id] ? "Marked Complete" : "Mark Complete"}</button>
        <button class="button secondary" id="save-note">Save Note</button>
      </div>
    </div>`;
  $("mark-done").onclick = () => { progress[id] = true; saveProgress(); renderLessons(document.querySelector("#module-filters .active")?.dataset.module || "all"); openLesson(id); };
  $("save-note").onclick = () => { notes[id] = $("lesson-note").value; saveNotes(); alert("Saved locally in this browser."); };
  location.hash = "lesson-view";
}

function renderSystemDesigns() {
  $("system-design-wrap").innerHTML = SYSTEM_DESIGNS.map(d => `
    <article class="card">
      <h3>${d.title}</h3>
      ${flowDiagram(d.steps)}
      <p><b>Strong answer:</b> ${d.answer}</p>
      <details><summary>Trade-offs to mention</summary><ul>${d.tradeoffs.map(t=>`<li>${t}</li>`).join("")}</ul></details>
    </article>`).join("");
}

function renderInterviewFilters() {
  const cats = ["All", ...new Set(INTERVIEWS.map(i=>i.category))];
  $("interview-filters").innerHTML = cats.map((c,i)=>`<button class="${i===0?'active':''}" data-cat="${c}">${c}</button>`).join("");
  $("interview-filters").querySelectorAll("button").forEach(btn => btn.onclick = () => {
    $("interview-filters").querySelectorAll("button").forEach(b=>b.classList.remove("active"));
    btn.classList.add("active");
    renderInterviews(btn.dataset.cat);
  });
}

function renderInterviews(cat="All") {
  const items = cat==="All" ? INTERVIEWS : INTERVIEWS.filter(i=>i.category===cat);
  $("interview-wrap").innerHTML = items.map(i => `
    <details class="qa">
      <summary><span class="cat">${i.category}</span>${i.question}</summary>
      <div class="ans"><p>${i.answer}</p></div>
    </details>`).join("");
}

function renderGlossary() {
  $("glossary-wrap").innerHTML = Object.entries(GLOSSARY).sort().map(([term,def]) => `
    <div class="term"><strong>${term}</strong><span>${def}</span></div>`).join("");
}

function renderStoryVault() {
  const prompts = [
    ["flagship","Flagship AI platform story"],
    ["product","Product/UX AI story"],
    ["program","AI program leadership story"],
    ["failure","Failure/lesson learned story"]
  ];
  const store = JSON.parse(localStorage.getItem("athena_v2_story_vault") || "{}");
  $("story-vault-wrap").innerHTML = prompts.map(([id,title]) => `
    <div class="scaffold">
      <h3>${title}</h3>
      <p class="small">Write privately: 30-second version, 2-minute version, whiteboard, trade-offs, outcome, lesson.</p>
      <textarea data-story="${id}" placeholder="Keep sensitive details out of public deployments.">${store[id] || ""}</textarea>
      <button class="button secondary" data-save-story="${id}">Save locally</button>
    </div>`).join("");
  $("story-vault-wrap").onclick = e => {
    const id = e.target.dataset.saveStory;
    if(!id) return;
    const updated = JSON.parse(localStorage.getItem("athena_v2_story_vault") || "{}");
    updated[id] = document.querySelector(`textarea[data-story="${id}"]`).value;
    localStorage.setItem("athena_v2_story_vault", JSON.stringify(updated));
    alert("Saved locally in this browser.");
  };
}

function buildSearchIndex() {
  const lessonItems = LESSONS.map(l=>({type:"Lesson",title:l.title,text:[l.module,l.tags.join(" "),l.analogy,l.simple,l.technical,l.principal,l.interview].join(" "),id:l.id,hash:"lesson-view"}));
  const interviewItems = INTERVIEWS.map((i,idx)=>({type:"Interview",title:i.question,text:i.answer+" "+i.category,id:"interview-"+idx,hash:"interview-bank"}));
  const glossaryItems = Object.entries(GLOSSARY).map(([term,def])=>({type:"Glossary",title:term,text:def,id:term,hash:"glossary"}));
  const sysItems = SYSTEM_DESIGNS.map((d,idx)=>({type:"System Design",title:d.title,text:d.steps.join(" ")+" "+d.tradeoffs.join(" ")+" "+d.answer,id:"sys-"+idx,hash:"system-design"}));
  return [...lessonItems,...interviewItems,...glossaryItems,...sysItems];
}

const SEARCH_INDEX = buildSearchIndex();

function renderSearch(q="") {
  const out = $("search-results");
  const query = q.trim().toLowerCase();
  if(!query) { out.innerHTML = `<p class="muted">Type a topic to search Athena.</p>`; return; }
  const results = SEARCH_INDEX.filter(item => (item.title+" "+item.text+" "+item.type).toLowerCase().includes(query)).slice(0,12);
  out.innerHTML = results.length ? results.map(r => `
    <a class="search-result" href="#${r.hash}" data-open="${r.type==='Lesson'?r.id:''}">
      <b>${r.type} · ${r.title}</b>
      <span>${r.text.slice(0,180)}...</span>
    </a>`).join("") : `<p class="muted">No results found.</p>`;
  out.querySelectorAll("[data-open]").forEach(a => a.onclick = () => { if(a.dataset.open) setTimeout(()=>openLesson(a.dataset.open),50); });
}

$("search-input").addEventListener("input", e => renderSearch(e.target.value));

renderFilters();
renderLessons();
renderSystemDesigns();
renderInterviewFilters();
renderInterviews();
renderGlossary();
renderStoryVault();
renderSearch();
